SELECT

FROM tb_member a

    a.del_flag = #{DEL_FLAG_NORMAL}


            AND a.enable_flag = #{query.enableFlag}


            AND a.email LIKE CONCAT('%', #{query.email}, '%')


            AND a.name LIKE CONCAT('%', #{query.name}, '%')


            AND a.remarks LIKE CONCAT('%', #{query.remarks}, '%')


            AND a.register_date BETWEEN #{query.beginRegisterDate} AND #{query.endRegisterDate}


            AND a.last_login_date BETWEEN #{query.beginLoginDate} AND #{query.endLoginDate}


            and a.mobile = #{query.mobile}



ORDER BY a.priority, a.email

